  ('elementary-f29af906-moex-00888', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '重新實施地籍測量之結果，應予公告，依土地法規定，公告期間為下列何者？', '["六十日", "三十日", "十五日", "十日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00889', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法規定，下列有關登記費免納之敘述，何者錯誤？', '["限制登記免納登記費", "因土地重劃之變更登記免納登記費", "繼承登記免納登記費", "更名登記免納登記費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00890', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '甲、乙、丙、丁四人分別共有一筆水源地A地，各持分四分之一，下列敘述何者正確？', '["甲、乙、丙、丁將A地出租給外國人，該契約無效", "甲、乙將A地出租給本國人，該契約有效", "甲、乙、丙將A地出賣給外國人，該契約有效", "甲未得乙、丙、丁之全體同意，不得請求分割A地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00891', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '下列何者與公寓大廈管理條例之規定不符？', '["區分所有權人會議之召開，除有急迫情事須召開臨時會之情形外，應由召集人於開會前十日以公告為之", "住戶於公寓大廈內依法經營危險營業者，應依中央主管機關所定保險金額投保公共意外責任保險", "管理委員之選任事項，不得以臨時動議提出", "禁止住戶飼養動物之特別約定，非經載明於規約者，不生效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
