  ('elementary-f29af906-moex-00893', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '國有學產不動產撥供公立學校、道路使用者，下列敘述何者正確？', '["撥供公立學校使用者為有償撥用、撥供道路使用者為無償撥用", "撥供公立學校使用者為無償撥用、撥供道路使用者為有償撥用", "兩者皆為無償撥用", "兩者皆為有償撥用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00894', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依離島建設條例規定，開放離島設置觀光賭場，應依公民投票法先辦理地方性公民投票，其公民投票結 果應達之比例為何者？', '["投票人數應超過縣（市）投票權人數總數二分之一，且有效投票票數超過二分之一同意", "有效投票票數超過二分之一同意，投票人數不受縣（市）投票權人數總數二分之一以上之限制", "有效投票票數達三分之一以上同意，投票人數不受縣（市）投票權人數總數二分之一以上之限制", "投票人數應達縣（市）投票權人數總數二分之一以上，且有效投票票數達二分之一以上同意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00895', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，下列何者為土地徵收之原土地所有權人得行使收回權之事由？', '["公告徵收時，都市計畫已規定以聯合開發、市地重劃或其他方式開發", "未依核准徵收原定興辦事業使用", "依徵收計畫開始使用前，興辦之事業改變、興辦事業計畫經註銷、開發方式改變或取得方式改變", "已依徵收計畫開始使用，尚未依徵收計畫完成使用之土地，因情事變更，致原徵收土地之全部或一部 已無徵收之必要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00896', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，內政部申請區段徵收，其核准機關為下列何者？', '["無須核准", "內政部", "行政院", "該管直轄市、縣（市）政府"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00897', 'elementary-f29af906', 'elementary-f29af906-moex-110-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，對於徵收公告事項提出異議者，其程序應為下列何者？', '["於公告期間內向該管直轄市或縣（市）主管機關以書面提出", "於公告期間屆滿次日起三十日內向該管直轄市或縣（市）主管機關以書面提出", "於公告期間內向內政部以書面提出", "於公告期間屆滿次日起三十日內向內政部以書面提出"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "adea1da9374e", "answer_pdf_sha1": "4b828ac3b6b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
